import{_ as e,o as r,c as i,ag as a}from"./chunks/framework.6MCaaFDc.js";const u=JSON.parse('{"title":"Network Security","description":"","frontmatter":{},"headers":[],"relativePath":"theory/networks/network-security.md","filePath":"theory/networks/network-security.md"}'),n={name:"theory/networks/network-security.md"};function s(o,t,d,l,c,p){return r(),i("div",null,[...t[0]||(t[0]=[a(`<h1 id="network-security" tabindex="-1">Network Security <a class="header-anchor" href="#network-security" aria-label="Permalink to &quot;Network Security&quot;">​</a></h1><p>Every time data travels across a network, it could be intercepted, altered, or stolen. Network security is about ensuring that only authorised people can access data, and that the data arriving is exactly what was sent.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 12</p><p>Network security (encryption, SSL/TLS, public/private keys, certificates) is a Grade 12 topic.</p></div><hr><h2 id="why-network-security-matters" tabindex="-1">Why Network Security Matters <a class="header-anchor" href="#why-network-security-matters" aria-label="Permalink to &quot;Why Network Security Matters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Threat</th><th>What could happen</th></tr></thead><tbody><tr><td>Eavesdropping</td><td>Attacker intercepts unencrypted data in transit</td></tr><tr><td>Man-in-the-middle</td><td>Attacker intercepts and alters data between two parties</td></tr><tr><td>Identity spoofing</td><td>Attacker pretends to be a trusted server</td></tr><tr><td>Data theft</td><td>Sensitive data (passwords, banking) stolen in transit</td></tr><tr><td>Denial of Service</td><td>Attacker floods network to make it unavailable</td></tr></tbody></table><hr><h2 id="encryption" tabindex="-1">Encryption <a class="header-anchor" href="#encryption" aria-label="Permalink to &quot;Encryption&quot;">​</a></h2><p><strong>Encryption</strong> is the process of scrambling data so that it can only be read by someone with the correct key.</p><ul><li><strong>Plaintext</strong> → encrypted using a key → <strong>ciphertext</strong></li><li>Only someone with the correct <strong>decryption key</strong> can reverse the process</li><li>Without the key, intercepted ciphertext is unreadable</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Original:  &quot;Transfer R5000 to account 1234&quot;</span></span>
<span class="line"><span>Encrypted: &quot;Xk9#mP2!vL8@qR7$...&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="why-encrypt" tabindex="-1">Why encrypt? <a class="header-anchor" href="#why-encrypt" aria-label="Permalink to &quot;Why encrypt?&quot;">​</a></h3><ul><li>Protects data in transit (over the internet)</li><li>Protects data at rest (stored on disk)</li><li>Ensures only the intended recipient can read the message</li></ul><hr><h2 id="symmetric-encryption" tabindex="-1">Symmetric Encryption <a class="header-anchor" href="#symmetric-encryption" aria-label="Permalink to &quot;Symmetric Encryption&quot;">​</a></h2><p>Both sender and receiver use the <strong>same key</strong> to encrypt and decrypt.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sender: plaintext + key → ciphertext</span></span>
<span class="line"><span>Receiver: ciphertext + same key → plaintext</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><table tabindex="0"><thead><tr><th>Advantage</th><th>Disadvantage</th></tr></thead><tbody><tr><td>Very fast</td><td>Key must be securely shared — how?</td></tr><tr><td>Simple</td><td>If key is intercepted, all data is compromised</td></tr></tbody></table><p><strong>Examples:</strong> AES (Advanced Encryption Standard), DES</p><hr><h2 id="asymmetric-encryption-public-key-cryptography" tabindex="-1">Asymmetric Encryption (Public Key Cryptography) <a class="header-anchor" href="#asymmetric-encryption-public-key-cryptography" aria-label="Permalink to &quot;Asymmetric Encryption (Public Key Cryptography)&quot;">​</a></h2><p>Uses <strong>two mathematically linked keys</strong>:</p><ul><li><strong>Public key</strong> — shared openly with everyone</li><li><strong>Private key</strong> — kept secret by the owner</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sender encrypts with recipient&#39;s PUBLIC key</span></span>
<span class="line"><span>↓</span></span>
<span class="line"><span>Only the recipient&#39;s PRIVATE key can decrypt it</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><table tabindex="0"><thead><tr><th>Advantage</th><th>Disadvantage</th></tr></thead><tbody><tr><td>No need to share a secret key</td><td>Much slower than symmetric encryption</td></tr><tr><td>Public key can be freely distributed</td><td>Computationally intensive</td></tr><tr><td>Even if public key is intercepted, data is safe</td><td></td></tr></tbody></table><p><strong>Examples:</strong> RSA, ECC (Elliptic Curve Cryptography)</p><h3 id="digital-signatures" tabindex="-1">Digital Signatures <a class="header-anchor" href="#digital-signatures" aria-label="Permalink to &quot;Digital Signatures&quot;">​</a></h3><p>The reverse process — encrypt with your <strong>private key</strong>, others verify with your <strong>public key</strong>:</p><ul><li>Proves the message came from you (authentication)</li><li>Proves the message was not altered (integrity)</li></ul><hr><h2 id="ssl-tls" tabindex="-1">SSL / TLS <a class="header-anchor" href="#ssl-tls" aria-label="Permalink to &quot;SSL / TLS&quot;">​</a></h2><p><strong>SSL</strong> (Secure Sockets Layer) and its successor <strong>TLS</strong> (Transport Layer Security) are cryptographic protocols that secure communication over the internet.</p><p>TLS is what makes HTTPS work.</p><h3 id="how-tls-works-simplified-handshake" tabindex="-1">How TLS works (simplified handshake): <a class="header-anchor" href="#how-tls-works-simplified-handshake" aria-label="Permalink to &quot;How TLS works (simplified handshake):&quot;">​</a></h3><ol><li>Client connects to server: &quot;Hello — I want a secure connection&quot;</li><li>Server sends its <strong>digital certificate</strong> (contains public key)</li><li>Client verifies the certificate (is it signed by a trusted CA?)</li><li>Client and server agree on a <strong>session key</strong> (symmetric) using asymmetric encryption</li><li>All further communication encrypted with the session key</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTPS = HTTP + TLS encryption</span></span>
<span class="line"><span>http://  → unencrypted (avoid for sensitive data)</span></span>
<span class="line"><span>https:// → encrypted with TLS</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="visual-indicators-in-a-browser" tabindex="-1">Visual indicators in a browser: <a class="header-anchor" href="#visual-indicators-in-a-browser" aria-label="Permalink to &quot;Visual indicators in a browser:&quot;">​</a></h3><ul><li><strong>Padlock icon</strong> — TLS certificate present</li><li><code>https://</code> in the address bar</li><li>Certificate details: click padlock → certificate info</li></ul><hr><h2 id="digital-certificates" tabindex="-1">Digital Certificates <a class="header-anchor" href="#digital-certificates" aria-label="Permalink to &quot;Digital Certificates&quot;">​</a></h2><p>A <strong>digital certificate</strong> is an electronic document that proves the identity of a website or organisation.</p><p><strong>What a certificate contains:</strong></p><ul><li>Organisation name and domain</li><li>Public key of the organisation</li><li>Expiry date</li><li>Digital signature of the Certificate Authority (CA)</li></ul><p><strong>Certificate Authority (CA):</strong> A trusted organisation that issues and signs certificates (e.g., DigiCert, Let&#39;s Encrypt, Comodo, VeriSign).</p><p>When your browser visits <code>https://mybank.co.za</code>:</p><ol><li>Browser downloads the server&#39;s certificate</li><li>Checks if the CA is trusted (browser has a list of trusted CAs)</li><li>Verifies the signature is genuine</li><li>Confirms the domain matches the certificate</li></ol><p>If verification fails → browser shows a security warning.</p><hr><h2 id="firewalls" tabindex="-1">Firewalls <a class="header-anchor" href="#firewalls" aria-label="Permalink to &quot;Firewalls&quot;">​</a></h2><p>A <strong>firewall</strong> monitors and controls network traffic based on predefined security rules.</p><p><strong>What firewalls do:</strong></p><ul><li>Block traffic from suspicious IP addresses</li><li>Block specific ports (e.g., block port 23 — Telnet)</li><li>Allow only authorised protocols</li><li>Log traffic for audit purposes</li></ul><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Packet filtering</strong></td><td>Checks source/destination IP and port — allows or blocks</td></tr><tr><td><strong>Stateful inspection</strong></td><td>Tracks state of connections — knows if a packet is part of an existing session</td></tr><tr><td><strong>Application-layer (proxy)</strong></td><td>Inspects actual content of traffic</td></tr><tr><td><strong>Next-generation firewall</strong></td><td>Combines all above + deep packet inspection + threat intelligence</td></tr></tbody></table><hr><h2 id="vpn-—-virtual-private-network" tabindex="-1">VPN — Virtual Private Network <a class="header-anchor" href="#vpn-—-virtual-private-network" aria-label="Permalink to &quot;VPN — Virtual Private Network&quot;">​</a></h2><p>A <strong>VPN</strong> creates an encrypted &quot;tunnel&quot; through the internet, making the connection appear as if it&#39;s on a private network.</p><p><strong>Uses:</strong></p><ul><li>Remote workers securely accessing company network</li><li>Protecting data on public Wi-Fi</li><li>Anonymising internet browsing</li><li>Bypassing geographic content restrictions</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Your device → [Encrypted tunnel] → VPN server → Internet</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Without VPN on public Wi-Fi:</strong> data is readable by anyone on the same network<br><strong>With VPN:</strong> data is encrypted from your device to the VPN server</p><hr><h2 id="authentication-methods" tabindex="-1">Authentication Methods <a class="header-anchor" href="#authentication-methods" aria-label="Permalink to &quot;Authentication Methods&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><strong>Password</strong></td><td>Secret string known only to user</td></tr><tr><td><strong>Two-factor authentication (2FA)</strong></td><td>Password + second factor (SMS OTP, app code)</td></tr><tr><td><strong>Biometrics</strong></td><td>Fingerprint, face recognition, iris scan</td></tr><tr><td><strong>Smart card</strong></td><td>Physical card with embedded chip</td></tr><tr><td><strong>Certificate-based</strong></td><td>Digital certificate verifies identity</td></tr></tbody></table><hr><h2 id="intrusion-detection-systems-ids" tabindex="-1">Intrusion Detection Systems (IDS) <a class="header-anchor" href="#intrusion-detection-systems-ids" aria-label="Permalink to &quot;Intrusion Detection Systems (IDS)&quot;">​</a></h2><p>An <strong>IDS</strong> monitors network traffic for suspicious activity and alerts administrators.</p><ul><li><strong>Passive IDS</strong>: detects and alerts only</li><li><strong>Active IDS (IPS — Intrusion Prevention System)</strong>: detects and automatically blocks</li></ul><hr><h2 id="https-vs-http" tabindex="-1">HTTPS vs HTTP <a class="header-anchor" href="#https-vs-http" aria-label="Permalink to &quot;HTTPS vs HTTP&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>HTTP</th><th>HTTPS</th></tr></thead><tbody><tr><td>Encryption</td><td>None</td><td>TLS encryption</td></tr><tr><td>Port</td><td>80</td><td>443</td></tr><tr><td>Data in transit</td><td>Readable by anyone</td><td>Encrypted — unreadable</td></tr><tr><td>Authentication</td><td>None</td><td>Certificate proves server identity</td></tr><tr><td>Use</td><td>Non-sensitive content</td><td>Login, banking, any sensitive data</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Encryption</strong></td><td>Scrambling data so only the key holder can read it</td></tr><tr><td><strong>Plaintext</strong></td><td>Original, unencrypted data</td></tr><tr><td><strong>Ciphertext</strong></td><td>Encrypted, scrambled data</td></tr><tr><td><strong>Symmetric encryption</strong></td><td>Same key used to encrypt and decrypt</td></tr><tr><td><strong>Asymmetric encryption</strong></td><td>Public key encrypts; private key decrypts</td></tr><tr><td><strong>Public key</strong></td><td>Key shared openly — used by others to encrypt messages to you</td></tr><tr><td><strong>Private key</strong></td><td>Secret key — only you can decrypt with it</td></tr><tr><td><strong>SSL/TLS</strong></td><td>Protocol securing internet communication (HTTPS)</td></tr><tr><td><strong>Digital certificate</strong></td><td>Electronic document proving a server&#39;s identity</td></tr><tr><td><strong>CA</strong></td><td>Certificate Authority — trusted organisation issuing certificates</td></tr><tr><td><strong>Firewall</strong></td><td>Security device filtering network traffic</td></tr><tr><td><strong>VPN</strong></td><td>Encrypted tunnel connecting devices over the internet</td></tr><tr><td><strong>2FA</strong></td><td>Two-factor authentication — requires two forms of verification</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Explain the difference between symmetric and asymmetric encryption&quot;</strong> — Symmetric: both parties use the same key (fast but key must be shared); Asymmetric: public key encrypts, only private key decrypts (secure but slower)</p></li><li><p><strong>&quot;What is a digital certificate? What does it contain?&quot;</strong> — Electronic document proving a server&#39;s identity; contains: organisation name, domain, public key, CA digital signature, expiry date</p></li><li><p><strong>&quot;Explain how HTTPS protects data&quot;</strong> — Uses TLS to encrypt all data in transit; only the server&#39;s private key can decrypt it; certificate verifies server identity</p></li><li><p><strong>&quot;What is the purpose of a firewall?&quot;</strong> — Monitors and controls network traffic based on security rules; blocks unauthorised access while allowing legitimate traffic</p></li><li><p><strong>&quot;Why should you use a VPN on public Wi-Fi?&quot;</strong> — Public Wi-Fi is unencrypted — anyone on the network can read your data; a VPN creates an encrypted tunnel protecting your data from eavesdropping</p></li></ol></div>`,76)])])}const y=e(n,[["render",s]]);export{u as __pageData,y as default};
